// // This module selects between two 128-bit wide input signals, `inb` and `ina`, based on the value of the control signal `sel`. When `sel` is 0, the output `out` reflects the value of `ina`, and when `sel` is 1, the output reflects the value of `inb`.
module top_module(ina, inb, out, sel);//INPUTS
    input [0:127] ina, inb;
    input sel;

    // OUTPUTS
    output [0:127] out;

    // REGISTERS
    reg [0:127] out;

    always @ (ina or inb or sel)
        begin
        out<= sel ? ina : inb;
        end // always @ (ina or inb or sel)
endmodule
